function useLocalStorage(key, initialValue) {
  const [storedValue, setStoredValue] = useState(() => {
    if (typeof window === 'undefined') return initialValue;
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch { return initialValue; }
  });

  const setValue = useCallback((value) => {
    const valueToStore = value instanceof Function ? value(storedValue) : value;
    setStoredValue(valueToStore);
    window.localStorage.setItem(key, JSON.stringify(valueToStore));
  }, [key, storedValue]);

  return [storedValue, setValue];
}

function formReducer(state, action) {
  switch (action.type) {
    case 'SET_FIELD': return { ...state, values: { ...state.values, [action.field]: action.value }, touched: { ...state.touched, [action.field]: true } };
    case 'SET_ERROR': return { ...state, errors: { ...state.errors, [action.field]: action.error } };
    case 'SUBMIT': return { ...state, isSubmitting: true };
    case 'SUBMIT_DONE': return { ...state, isSubmitting: false };
    case 'RESET': return { values: action.initial, errors: {}, touched: {}, isSubmitting: false };
    default: return state;
  }
}

function useFormState(initialValues) {
  const [state, dispatch] = useReducer(formReducer, { values: initialValues, errors: {}, touched: {}, isSubmitting: false });
  const setField = (field, value) => dispatch({ type: 'SET_FIELD', field, value });
  return { ...state, setField, dispatch };
}

function useBreakpoint() {
  const [breakpoint, setBreakpoint] = useState('xs');

  useEffect(() => {
    const getBreakpoint = () => {
      const w = window.innerWidth;
      if (w >= 1280) return 'xl';
      if (w >= 1024) return 'lg';
      if (w >= 768) return 'md';
      if (w >= 640) return 'sm';
      return 'xs';
    };
    const handler = () => setBreakpoint(getBreakpoint());
    handler();
    window.addEventListener('resize', handler);
    return () => window.removeEventListener('resize', handler);
  }, []);

  return breakpoint;
}

function useQueue(initialItems = []) {
  const [queue, setQueue] = useState(initialItems);

  const enqueue = useCallback((item) => setQueue(q => [...q, item]), []);
  const dequeue = useCallback(() => {
    let removed;
    setQueue(q => { removed = q[0]; return q.slice(1); });
    return removed;
  }, []);
  const peek = queue[0];
  const size = queue.length;
  const clear = useCallback(() => setQueue([]), []);

  return { queue, enqueue, dequeue, peek, size, clear };
}

function createSelectableContext(defaultValue) {
  const Context = createContext(defaultValue);
  const listeners = new Set();
  let currentValue = defaultValue;

  function Provider({ value, children }) {
    currentValue = value;
    useEffect(() => {
      listeners.forEach(listener => listener());
    });
    return <Context.Provider value={value}>{children}</Context.Provider>;
  }

  function useSelector(selector) {
    const [, forceRender] = useReducer(c => c + 1, 0);
    const selectedRef = useRef(selector(currentValue));

    useEffect(() => {
      const check = () => {
        const next = selector(currentValue);
        if (next !== selectedRef.current) {
          selectedRef.current = next;
          forceRender();
        }
      };
      listeners.add(check);
      return () => listeners.delete(check);
    }, [selector]);

    return selectedRef.current;
  }

  return { Provider, useSelector };
}
